import{_ as d,o as r,c as a,ai as e}from"./chunks/framework.CaiDwmc7.js";const x=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"Roadmap.md","filePath":"Roadmap.md"}'),h={name:"Roadmap.md"};function o(b,t,l,n,i,s){return r(),a("div",null,[...t[0]||(t[0]=[e('<h2 id="фаза-0-пре-продакшн" tabindex="-1">ФАЗА 0: ПРЕ-ПРОДАКШН <a class="header-anchor" href="#фаза-0-пре-продакшн" aria-label="Permalink to “ФАЗА 0: ПРЕ-ПРОДАКШН”">​</a></h2><table tabindex="0"><thead><tr><th>Задача</th><th>Эпик</th></tr></thead><tbody><tr><td>Создать структуру папок в обсидиан</td><td>6</td></tr><tr><td>Настроить общий доступ для команды</td><td>6</td></tr><tr><td>Написать One-Pager</td><td>6</td></tr><tr><td>Сделать репозитории в организации на GitHub для</td><td>6</td></tr><tr><td>Собрать мудборд</td><td>4</td></tr></tbody></table><p><strong>Критерий готовности:</strong> готовый штаб проекта, команда в курсе целей</p><hr><hr><h2 id="фаза-1-прототип" tabindex="-1">ФАЗА 1: ПРОТОТИП <a class="header-anchor" href="#фаза-1-прототип" aria-label="Permalink to “ФАЗА 1: ПРОТОТИП”">​</a></h2><h4 id="дизаин-документация-по-пчелам" tabindex="-1">Дизайн-документация по пчелам <a class="header-anchor" href="#дизаин-документация-по-пчелам" aria-label="Permalink to “Дизайн-документация по пчелам”">​</a></h4><table tabindex="0"><thead><tr><th>Задача</th><th>Эпик</th></tr></thead><tbody><tr><td>Документация. Типы пчел и их роли: рабочие пчелы, трутни королева</td><td>1</td></tr><tr><td>Документация. Состояния и поведение пчел: активность, здоровье, настроение, действия</td><td>1</td></tr><tr><td>Документация. Система здоровья и жизненный цикл: продолжительность жизни пчел, факторы, влияющие на здоровье, таблица болезней</td><td>1</td></tr><tr><td>Документация. Взаимодействие с миром: какие цветы дают какую пыльцу, любимые цветы разных типов пчел, влияние погоды, влияние времени суток</td><td>1</td></tr><tr><td>Документация. Случайные события: роение, вредители, появление новой королевы, болезни и эпидемии, хищники и нападение на улей</td><td>1</td></tr><tr><td>Документация. Экономика улья: формулы производства меда, скорость размножения, баланс состава роя, таблица всех параметров</td><td>1</td></tr><tr><td><strong>Критерий готовности:</strong> полный пакет дизайн-документов по пчелам.</td><td></td></tr></tbody></table><hr><h4 id="ядро-механики" tabindex="-1">Ядро механики <a class="header-anchor" href="#ядро-механики" aria-label="Permalink to “Ядро механики”">​</a></h4><table tabindex="0"><thead><tr><th>Задача</th><th>Эпик</th></tr></thead><tbody><tr><td>Базовый улей</td><td>1</td></tr><tr><td>Базовое взаимодействие с ульем согласно Core Loop</td><td>1</td></tr><tr><td>UI-заглушка меню для сбора меда</td><td>1</td></tr><tr><td>Базовый инвентарь для сбора меда как ресурса</td><td>1</td></tr><tr><td>Привязать сбор к наполнению улья и появлению меда в инвентаре</td><td>1</td></tr><tr><td><strong>Критерий готовности:</strong> можно подойти к улью, нажать кнопку, получить мед в инвентарь</td><td></td></tr></tbody></table><hr><h4 id="экономика" tabindex="-1">Экономика <a class="header-anchor" href="#экономика" aria-label="Permalink to “Экономика”">​</a></h4><table tabindex="0"><thead><tr><th>Задача</th><th>Эпик</th></tr></thead><tbody><tr><td>Объект &quot;Торговец&quot; (заглушка)</td><td>1</td></tr><tr><td>UI-заглушка продажи (кнопка &quot;Продать&quot;)</td><td>1</td></tr><tr><td>Валюта (очки/монеты/что-то еще) и привязать к продаже</td><td>1</td></tr><tr><td>Добавить фукнцию покупки улучшения</td><td>1</td></tr><tr><td>Протестировать цикл: собрал -&gt; продал -&gt; купил</td><td>1</td></tr><tr><td>Настроить параметры для баланса</td><td>1</td></tr><tr><td><strong>Критерия готовности:</strong> на кубах реализован Core Loop, можно играть в кубы</td><td></td></tr></tbody></table><hr><h4 id="первыи-нпс-и-квест" tabindex="-1">Первый нпс и квест <a class="header-anchor" href="#первыи-нпс-и-квест" aria-label="Permalink to “Первый нпс и квест”">​</a></h4><table tabindex="0"><thead><tr><th>Задача</th><th>Эпик</th></tr></thead><tbody><tr><td>Разместить заглушку НПС на сцене</td><td>2</td></tr><tr><td>Реализовать простую систему диалогов (окно с текстом)</td><td>2</td></tr><tr><td>Написать первую версию реплик (приветствие, задача)</td><td>2</td></tr><tr><td>Создать систему целей (простейшая цепочка квестов для обучения и реализации Core Loop)</td><td>2</td></tr><tr><td>Привязать проверку выполнения к действиям игрока (взаимодействия с кубом-ульем) и инвентарю</td><td>2</td></tr><tr><td>Тест: прохождение от начала до конца Core Loop</td><td>1, 2</td></tr><tr><td><strong>Критерий готовности:</strong> есть НПС, есть цель, цикл работает, прототип готов.</td><td></td></tr></tbody></table><hr><h4 id="пчелиная-логика-базовая" tabindex="-1">Пчелиная логика - базовая <a class="header-anchor" href="#пчелиная-логика-базовая" aria-label="Permalink to “Пчелиная логика - базовая”">​</a></h4><table tabindex="0"><thead><tr><th>Задача</th><th>Эпик</th></tr></thead><tbody><tr><td>Реализация индивидуального поведения пчелы</td><td>1</td></tr><tr><td>Индикаторы для пчелы: здоровье, энергия, статус</td><td>1</td></tr><tr><td>Реализация системы роя (группа пчел в улье)</td><td>1</td></tr><tr><td>Улей содержит список пчел, пчелы вылетают и возвращаются</td><td>1</td></tr><tr><td>Реализация сбора пыльцы: пчелы летают к цветам и возвращаются в улей</td><td>1</td></tr><tr><td>Связать активность и количество пчел с производством меда</td><td>1</td></tr><tr><td>Добавить базовые индикаторы состояния: число пчел в улье, статус</td><td>1</td></tr><tr><td>Тестирование базовой логики пчелиного поведения</td><td>1</td></tr><tr><td><strong>Критерий готовности:</strong> пчелы живут своей жизнью: летают к цветам, возвращаются, влияют на производство меда.</td><td></td></tr></tbody></table><hr><hr><h2 id="фаза-2-контент-и-углубление-логики" tabindex="-1">ФАЗА 2: КОНТЕНТ И УГЛУБЛЕНИЕ ЛОГИКИ <a class="header-anchor" href="#фаза-2-контент-и-углубление-логики" aria-label="Permalink to “ФАЗА 2: КОНТЕНТ И УГЛУБЛЕНИЕ ЛОГИКИ”">​</a></h2><h4 id="визуальныи-стиль-основные-объекты" tabindex="-1">Визуальный стиль: основные объекты <a class="header-anchor" href="#визуальныи-стиль-основные-объекты" aria-label="Permalink to “Визуальный стиль: основные объекты”">​</a></h4><table tabindex="0"><thead><tr><th>Задача</th><th>Эпик</th></tr></thead><tbody><tr><td>Утвердить цветовую палитру и стиль</td><td>4</td></tr><tr><td>Модель улья (3 состояния: пустой/средний/полный)</td><td>4</td></tr><tr><td>Иконки для базового UI, входящего в геймплей Core Loop</td><td>4</td></tr><tr><td>Базовая модель игрока для минимального функционала</td><td>4</td></tr><tr><td>Базовая модель НПС</td><td>4</td></tr><tr><td>Базовая модель пчел разных видов</td><td></td></tr><tr><td><strong>Критерий готовности:</strong> ульи и персонажы перестали быть серыми кубами, стали серыми объектами</td><td></td></tr></tbody></table><hr><h4 id="центральная-локация" tabindex="-1">Центральная локация <a class="header-anchor" href="#центральная-локация" aria-label="Permalink to “Центральная локация”">​</a></h4><table tabindex="0"><thead><tr><th>Задача</th><th>Эпик</th></tr></thead><tbody><tr><td>Создать концепцию карты (схема пасеки)</td><td>3</td></tr><tr><td>Нарисовать фон для пасеки (небо, дальний план)</td><td>4</td></tr><tr><td>Нарисовать дом пасечника (фасад)</td><td>4</td></tr><tr><td>Разместить все объекты в движке (расстановка)</td><td>3</td></tr><tr><td>Добавить декор (цветы, траву, забор)</td><td>3, 4</td></tr><tr><td>Настроить коллизии и освещение</td><td>3</td></tr><tr><td>Связать пчел с медоносами на локации</td><td>1, 3</td></tr><tr><td>Система &quot;любимых&quot; цветов у пчел: определенные цветы повышают настроение/продуктивность</td><td>1</td></tr><tr><td><strong>Критерий готовности:</strong> пасека выглядит как настоящее место, а не тестовая комната</td><td></td></tr></tbody></table><hr><h4 id="пчелиная-логика-продвинутая" tabindex="-1">Пчелиная логика - продвинутая <a class="header-anchor" href="#пчелиная-логика-продвинутая" aria-label="Permalink to “Пчелиная логика - продвинутая”">​</a></h4><table tabindex="0"><thead><tr><th>Задача</th><th>Эпик</th></tr></thead><tbody><tr><td>Реализация разных типов пчел с уникальным поведением: рабочие, трутни, королева</td><td>1</td></tr><tr><td>Добавление системы здоровья пчел: рост и снижение популяции, болезни</td><td>1</td></tr><tr><td>Реализация смены состояний пчел: спокойные/активные, сбор пыльцы/отдых, больные, агрессивные, реакция на время суток</td><td>1</td></tr><tr><td>Добавить систему погоды и реакцию пчел: дождь, ветер, холод, жара</td><td>1</td></tr><tr><td>Интегрировать состояния в UI</td><td>1</td></tr><tr><td>Реализовать случайные события: роение, болезни, вредители, появление новой королевы</td><td>1</td></tr><tr><td>Система уведомлений</td><td></td></tr><tr><td><strong>Критерий готовности:</strong> пчелы ведут себя как живые</td><td></td></tr></tbody></table><hr><h4 id="звук-и-интерфеис" tabindex="-1">Звук и интерфейс <a class="header-anchor" href="#звук-и-интерфеис" aria-label="Permalink to “Звук и интерфейс”">​</a></h4><table tabindex="0"><thead><tr><th>Задача</th><th>Эпик</th></tr></thead><tbody><tr><td>Найти/сделать фоновые звуки</td><td>5</td></tr><tr><td>Найти сделать звуки для разных состояний пчел: спокойное, активное, тревожное, звук отдельной пчелы</td><td>5</td></tr><tr><td>Найти/создать звуки действий игрока</td><td>5</td></tr><tr><td>Найти/создать главную музыкальную тему (для меню)</td><td>5</td></tr><tr><td>Создать UI индикаторов состояния улья и роя</td><td>1, 4</td></tr><tr><td>Интегрировать звуки и UI в движок</td><td>4, 5</td></tr><tr><td><strong>Критерий готовности:</strong> мир зазвучал, есть инструменты для сбора обратной связи от мира для игрока</td><td></td></tr></tbody></table><hr><hr><h2 id="фаза-3-полировка-и-интеграция" tabindex="-1">ФАЗА 3: ПОЛИРОВКА И ИНТЕГРАЦИЯ <a class="header-anchor" href="#фаза-3-полировка-и-интеграция" aria-label="Permalink to “ФАЗА 3: ПОЛИРОВКА И ИНТЕГРАЦИЯ”">​</a></h2><h4 id="интерфеис-и-нарратив" tabindex="-1">Интерфейс и нарратив <a class="header-anchor" href="#интерфеис-и-нарратив" aria-label="Permalink to “Интерфейс и нарратив”">​</a></h4><table tabindex="0"><thead><tr><th>Задача</th><th>Эпик</th></tr></thead><tbody><tr><td>Финальный Ui и HUD (индикаторы)</td><td>4</td></tr><tr><td>Интегрировать интерфейс в движок</td><td>1, 4</td></tr><tr><td>Детальная информация об улье</td><td>1</td></tr><tr><td>Окно инвентаря (дизайн + интеграция)</td><td>1, 4</td></tr><tr><td>Окно диалога (дизайн + интеграция)</td><td>2, 4</td></tr><tr><td>Финальные версии диалогов</td><td>2</td></tr><tr><td>Звуки интерфейса</td><td>5</td></tr><tr><td>Реализовать главное меню</td><td>4</td></tr><tr><td><strong>Критерий готовности:</strong> интерфейс и индикаторы удобные и функциональные, данные обновляются, игроку удобно пользоваться</td><td></td></tr></tbody></table><hr><h4 id="атмосфера-и-события" tabindex="-1">Атмосфера и события <a class="header-anchor" href="#атмосфера-и-события" aria-label="Permalink to “Атмосфера и события”">​</a></h4><table tabindex="0"><thead><tr><th>Задача</th><th>Эпик</th></tr></thead><tbody><tr><td>Добавить описания объектам</td><td>2</td></tr><tr><td>Добавить случайные события с пчелами (роение, нападение вредителей, болезни, появление новой королевы)</td><td>1</td></tr><tr><td>Текст для вступительной кат-сцены</td><td>2</td></tr><tr><td>Вступительный экран (фон+текст)</td><td></td></tr><tr><td>Облака и динамика мира</td><td>3</td></tr><tr><td>Добавить размышления персонажа с пчелиными наблюдениями</td><td></td></tr></tbody></table><hr><h4 id="баланс-пчелинои-математики" tabindex="-1">Баланс пчелиной математики <a class="header-anchor" href="#баланс-пчелинои-математики" aria-label="Permalink to “Баланс пчелиной математики”">​</a></h4><table tabindex="0"><thead><tr><th>Задача</th><th>Эпик</th></tr></thead><tbody><tr><td>Финальная настройка всех пчелиных показателей (файл Формулы для пчел)</td><td>1</td></tr><tr><td>Финальная настройка баланса цен</td><td>1</td></tr><tr><td>Проверить все переходы и коллизии</td><td>3</td></tr><tr><td>Прогнать игру от начала до конца без ошибок</td><td>Все</td></tr><tr><td>Оптимизация и исправление ошибок при необходимости</td><td>Все</td></tr></tbody></table><hr><h4 id="закрытое-тестирование" tabindex="-1">Закрытое тестирование <a class="header-anchor" href="#закрытое-тестирование" aria-label="Permalink to “Закрытое тестирование”">​</a></h4><table tabindex="0"><thead><tr><th>Задача</th><th>Эпик</th></tr></thead><tbody><tr><td>Собрать билд для тестирования</td><td>6</td></tr><tr><td>Финальная проверка всех сценариев поведения</td><td>1</td></tr><tr><td>Финальная проверка звука</td><td>5</td></tr><tr><td>Записать геймплейное видео</td><td>6</td></tr><tr><td>Пригласить 3-5 человек не из команды для тестирования</td><td>6</td></tr><tr><td>Собрать фидбек по игре</td><td>6</td></tr><tr><td>Собрать фидбек по пчелиной системе</td><td>6</td></tr><tr><td>Ретроспектива</td><td>6</td></tr></tbody></table>',48)])])}const m=d(h,[["render",o]]);export{x as __pageData,m as default};
